const MemoForm = () => {
  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        gap: 10,
        padding: 20,
        border: "1px solid #61dafb",
        marginTop: 20,
        width: 300,
      }}
    >
      <label>
        タイトル
        <input type="text" />
      </label>

      <label>
        内容
        <textarea />
      </label>

      <label>
        タグ
        <input type="text" />
      </label>

      <button>保存</button>
    </div>
  );
};

export default MemoForm;
